## components/ChatInterface.tsx

Restored modern chat colors and suggestion chip styling.

```tsx
import React, { useRef, useEffect } from 'react';
import { Message as MessageType } from '../types';
import { MessageBubble } from './MessageBubble';
import { InputArea } from './InputArea';
import { Loader2 } from 'lucide-react';

interface ChatInterfaceProps {
  messages: MessageType[];
  isLoading: boolean;
  onSendMessage: (text: string) => void;
  error: string | null;
  suggestions?: string[];
}

export const ChatInterface: React.FC<ChatInterfaceProps> = ({ 
  messages, 
  isLoading, 
  onSendMessage,
  error,
  suggestions = []
}) => {
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, isLoading, suggestions]);

  return (
    <div className="flex flex-col h-full bg-gray-50">
      {/* Messages Area */}
      <div className="flex-1 overflow-y-auto custom-scrollbar w-full">
        <div className="max-w-5xl mx-auto p-4 space-y-6 w-full min-h-full flex flex-col">
          {messages.map((msg) => (
            <MessageBubble key={msg.id} message={msg} />
          ))}

          {isLoading && (
             <div className="flex w-full justify-start animate-slide-up">
              <div className="flex max-w-[85%] gap-3 flex-row">
                 <div className="flex-shrink-0 h-8 w-8 flex items-center justify-center mt-1 bg-white text-orange-500 rounded-full border border-gray-100 shadow-sm">
                    <Loader2 size={16} className="animate-spin" />
                  </div>
                  <div className="bg-white text-gray-500 px-4 py-2 rounded-2xl rounded-tl-none border border-gray-100 shadow-sm text-sm flex items-center italic">
                    Finding the best spots...
                  </div>
              </div>
            </div>
          )}

          {error && (
              <div className="flex justify-center my-4">
                  <div className="bg-red-50 text-red-600 text-sm px-4 py-2 rounded-lg border border-red-100 shadow-sm">
                      {error}
                  </div>
              </div>
          )}

          {/* Suggestion Chips */}
          {!isLoading && suggestions.length > 0 && (
            <div className="flex flex-wrap gap-2 mt-2 animate-fade-in pl-11">
              {suggestions.map((suggestion, idx) => (
                <button
                  key={idx}
                  onClick={() => onSendMessage(suggestion)}
                  className="bg-white border border-gray-200 text-gray-600 hover:bg-orange-50 hover:text-orange-600 hover:border-orange-200 active:bg-orange-100 px-4 py-2 rounded-full text-sm transition-all shadow-sm"
                >
                  {suggestion}
                </button>
              ))}
            </div>
          )}

          <div ref={messagesEndRef} className="h-4" />
        </div>
      </div>

      {/* Input Area */}
      <div className="bg-white border-t border-gray-200 w-full z-10">
        <div className="max-w-5xl mx-auto">
          <InputArea onSend={onSendMessage} isLoading={isLoading} />
        </div>
      </div>
    </div>
  );
};
```

## components/MessageBubble.tsx

Restored standard message bubble styling.

```tsx
import React from 'react';
import ReactMarkdown from 'react-markdown';
import { Message } from '../types';
import { Bot, User, ExternalLink } from 'lucide-react';

interface MessageBubbleProps {
  message: Message;
}

export const MessageBubble: React.FC<MessageBubbleProps> = ({ message }) => {
  const isUser = message.role === 'user';

  return (
    <div className={`flex w-full ${isUser ? 'justify-end' : 'justify-start'} animate-slide-up`}>
      <div className={`flex max-w-[85%] gap-3 ${isUser ? 'flex-row-reverse' : 'flex-row'}`}>

        {/* Avatar */}
        <div className={`flex-shrink-0 h-8 w-8 flex items-center justify-center mt-1 rounded-full shadow-sm ${
          isUser ? 'bg-orange-100 text-orange-600' : 'bg-white border border-gray-100 text-orange-500'
        }`}>
          {isUser ? <User size={16} /> : <Bot size={16} />}
        </div>

        {/* Bubble */}
        <div className={`flex flex-col gap-1 ${isUser ? 'items-end' : 'items-start'}`}>
          <div
            className={`px-5 py-3 shadow-sm text-sm leading-relaxed ${
              isUser
                ? 'bg-orange-500 text-white rounded-2xl rounded-tr-none'
                : 'bg-white text-gray-800 border border-gray-100 rounded-2xl rounded-tl-none'
            }`}
          >
            {isUser ? (
              <p>{message.content}</p>
            ) : (
              <div className="prose prose-sm prose-orange max-w-none prose-p:my-1 prose-headings:my-2 prose-ul:my-1 prose-li:my-0">
                <ReactMarkdown>{message.content}</ReactMarkdown>
              </div>
            )}
          </div>

          {/* Grounding Sources (if any) */}
          {!isUser && message.groundingMetadata?.groundingChunks && message.groundingMetadata.groundingChunks.length > 0 && (
            <div className="ml-1 mt-1 flex flex-wrap gap-2 max-w-full">
              {message.groundingMetadata.groundingChunks.map((chunk, idx) => {
                if (!chunk.web?.uri) return null;
                return (
                  <a
                    key={idx}
                    href={chunk.web.uri}
                    target="_blank"
                    rel="noopener noreferrer"
                    className="inline-flex items-center gap-1 text-[10px] bg-white border border-gray-200 text-gray-500 hover:text-orange-600 hover:border-orange-200 px-2 py-1 rounded-md transition-colors shadow-sm"
                  >
                    <ExternalLink size={10} />
                    <span className="truncate max-w-[120px]">{chunk.web.title || 'Source'}</span>
                  </a>
                );
              })}
            </div>
          )}
        </div>
      </div>
    </div>
  );
};
```

## components/InputArea.tsx

Restored clean input styling.

```tsx
import React, { useState, KeyboardEvent } from 'react';
import { Send } from 'lucide-react';

interface InputAreaProps {
  onSend: (text: string) => void;
  isLoading: boolean;
}

export const InputArea: React.FC<InputAreaProps> = ({ onSend, isLoading }) => {
  const [input, setInput] = useState('');

  const handleSend = () => {
    if (input.trim() && !isLoading) {
      onSend(input);
      setInput('');
    }
  };

  const handleKeyDown = (e: KeyboardEvent<HTMLInputElement>) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  return (
    <div className="p-4">
      <div className="relative flex items-center">
        <input
          type="text"
          value={input}
          onChange={(e) => setInput(e.target.value)}
          onKeyDown={handleKeyDown}
          placeholder="Ask about food in Blok M..."
          disabled={isLoading}
          className="w-full bg-gray-50 border border-gray-300 text-gray-900 text-sm rounded-full focus:ring-orange-500 focus:border-orange-500 block pl-5 pr-12 py-3 outline-none transition-all disabled:opacity-50 placeholder:text-gray-400"
        />
        <button
          onClick={handleSend}
          disabled={!input.trim() || isLoading}
          className="absolute right-2 p-2 bg-orange-500 hover:bg-orange-600 disabled:bg-gray-300 text-white rounded-full transition-colors shadow-sm"
        >
          <Send size={16} />
        </button>
      </div>
    </div>
  );
};
```

To distinguish between information coming from your future **Fine-Tuned Data (Official)** and **Google Search**, I will implement a "Source Badge" system in the chat UI.

Here is the logic:
1.  **Google Search Info**: If the AI uses the Search Tool, the API returns `groundingMetadata`. We will detect this and show a **"🌐 Google Search"** badge.
2.  **Official Info**: If the AI answers *without* using the Search Tool (meaning it relied on its internal training/fine-tuned weights), we will show a **"✨ Official Data"** badge.

This provides the objective distinction you need for your thesis.

# Updated files:

## components/MessageBubble.tsx

Added logic to display a "Source Badge" at the bottom of the message.
- **Green Badge (Official Data):** Shown when no search metadata is present.
- **Blue Badge (Google Search):** Shown when search metadata is detected.

```tsx
import React from 'react';
import ReactMarkdown from 'react-markdown';
import { Message } from '../types';
import { Bot, User, ExternalLink, Database, Globe } from 'lucide-react';

interface MessageBubbleProps {
  message: Message;
}

export const MessageBubble: React.FC<MessageBubbleProps> = ({ message }) => {
  const isUser = message.role === 'user';

  // Detect source type
  const hasGrounding = message.groundingMetadata?.groundingChunks && message.groundingMetadata.groundingChunks.length > 0;
  const isOfficial = !isUser && !hasGrounding;

  return (
    <div className={`flex w-full ${isUser ? 'justify-end' : 'justify-start'} animate-slide-up`}>
      <div className={`flex max-w-[85%] gap-3 ${isUser ? 'flex-row-reverse' : 'flex-row'}`}>

        {/* Avatar */}
        <div className={`flex-shrink-0 h-8 w-8 flex items-center justify-center mt-1 rounded-full shadow-sm ${
          isUser ? 'bg-orange-100 text-orange-600' : 'bg-white border border-gray-100 text-orange-500'
        }`}>
          {isUser ? <User size={16} /> : <Bot size={16} />}
        </div>

        {/* Bubble */}
        <div className={`flex flex-col gap-1 ${isUser ? 'items-end' : 'items-start'}`}>
          <div
            className={`px-5 py-3 shadow-sm text-sm leading-relaxed ${
              isUser
                ? 'bg-orange-500 text-white rounded-2xl rounded-tr-none'
                : 'bg-white text-gray-800 border border-gray-100 rounded-2xl rounded-tl-none'
            }`}
          >
            {isUser ? (
              <p>{message.content}</p>
            ) : (
              <div className="prose prose-sm prose-orange max-w-none prose-p:my-1 prose-headings:my-2 prose-ul:my-1 prose-li:my-0">
                <ReactMarkdown>{message.content}</ReactMarkdown>
              </div>
            )}
          </div>

          {/* SOURCE INDICATORS (Thesis Requirement) */}
          {!isUser && (
            <div className="flex flex-wrap items-center gap-2 mt-1 ml-1 select-none">

              {/* 1. Source Badge */}
              {isOfficial ? (
                 <div className="inline-flex items-center gap-1 text-[10px] bg-green-50 text-green-700 px-2 py-0.5 rounded-full border border-green-100 font-medium" title="Answered using internal model knowledge (Fine-tuned data)">
                    <Database size={10} />
                    <span>Official Data</span>
                 </div>
              ) : (
                 <div className="inline-flex items-center gap-1 text-[10px] bg-blue-50 text-blue-600 px-2 py-0.5 rounded-full border border-blue-100 font-medium" title="Answered using live Google Search">
                    <Globe size={10} />
                    <span>Google Search</span>
                 </div>
              )}

              {/* 2. Web Citations (Only if Search was used) */}
              {hasGrounding && message.groundingMetadata?.groundingChunks?.map((chunk, idx) => {
                if (!chunk.web?.uri) return null;
                return (
                  <a
                    key={idx}
                    href={chunk.web.uri}
                    target="_blank"
                    rel="noopener noreferrer"
                    className="inline-flex items-center gap-1 text-[10px] bg-white border border-gray-200 text-gray-400 hover:text-orange-600 hover:border-orange-200 px-2 py-0.5 rounded-full transition-colors"
                  >
                    <ExternalLink size={10} />
                    <span className="truncate max-w-[100px]">{chunk.web.title || 'Source'}</span>
                  </a>
                );
              })}
            </div>
          )}
        </div>
      </div>
    </div>
  );
};
```

## services/geminiService.ts

Updated the system instruction to explicitly tell the AI to prioritize its internal knowledge (Official Data) when it is confident, which helps the "Official Data" badge appear more often for common questions.

```typescript
import { GoogleGenAI, Chat } from "@google/genai";
import { GroundingMetadata } from "../types";

// --- CONFIGURATION ---
// Paste your Fine-Tuned Model ID here (e.g., 'tunedModels/blok-m-thesis-v1')
// If you leave it as 'gemini-2.5-flash', 'Official Data' simply means 'Base Model Knowledge'.
const MODEL_ID = 'gemini-2.5-flash';

// Set to TRUE to allow fallback to Google Search.
// Set to FALSE to force 'Official Data' only (simulating a closed system).
const USE_SEARCH_GROUNDING = true;

// ---------------------

const SYSTEM_INSTRUCTION = `
You are a specialized Food & Beverage Guide for Blok M, Jakarta.

**SOURCE HIERARCHY (CRITICAL):**
1. **OFFICIAL DATA (Internal Knowledge):** If you know the answer confidently from your training data, use it. This is preferred for "Official" recommendations.
2. **EXTERNAL DATA (Search):** Only use Google Search if you do not know the answer or need real-time info (like "is it open right now?").

**STRICT SCOPE LIMITATIONS:**
1. **TOPIC LOCK:** You can ONLY discuss Food, Drinks, Restaurants, Cafes, Bars, and Street Food in Blok M.
2. **REFUSAL PROTOCOL:** If the user asks about anything else (e.g., politics, history, fashion shops, electronics, general life advice, or locations outside Blok M), you must politely REFUSE.
   - Example Refusal: "I'm just a foodie! I can only help you find good stuff to eat or drink in Blok M."
3. **STYLE:** Be helpful, casual, and brief. You are not a robot, you are a local guide.

**TASK:**
- Provide recommendations with price ranges when possible.
- If unsure if a place exists, admit it.
- Do not make up facts.
`;

export class GeminiService {
  private ai: GoogleGenAI;
  private chatSession: Chat | null = null;

  constructor() {
    const apiKey = process.env.API_KEY;
    if (!apiKey) {
      console.error("API_KEY is missing from environment variables");
    }
    this.ai = new GoogleGenAI({ apiKey: apiKey || '' });
  }

  private initChat() {
    const tools = [];
    if (USE_SEARCH_GROUNDING) {
      tools.push({ googleSearch: {} });
    }

    this.chatSession = this.ai.chats.create({
      model: MODEL_ID,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        tools: tools, 
        temperature: 0.7, // Normal creativity for conversation
        maxOutputTokens: 500, // Enough for a good food review, but not a novel
      },
    });
  }

  async *sendMessageStream(message: string) {
    if (!this.chatSession) {
      this.initChat();
    }

    try {
      const result = await this.chatSession!.sendMessageStream({ message });

      for await (const chunk of result) {
        const text = chunk.text;
        const groundingMetadata = chunk.candidates?.[0]?.groundingMetadata as GroundingMetadata | undefined;

        yield { text, groundingMetadata };
      }
    } catch (error) {
      console.error("Gemini API Error:", error);
      throw error;
    }
  }
}

To turn this into a polished **website** (similar to Perplexity or ChatGPT) and deploy it, I have updated the design to be cleaner, with a floating input bar and a professional navigation header.

Here are the design updates:
1.  **Floating Input Bar:** Instead of a mobile-style bar stuck to the bottom, the input is now a "floating capsule" with a shadow, centered on the screen. This is the standard design for modern AI websites.
2.  **Glassmorphism Header:** The header is now translucent (backdrop blur) with navigation links, making it feel like a proper web app.
3.  **Responsive Layout:** The chat container allows for a wider, comfortable reading experience on desktop.

