import { Message } from "../types";

/**
 * MongoDB Atlas Data API Configuration
 * To use this, you need to:
 * 1. Create a MongoDB Atlas account.
 * 2. Enable "Data API" in the Atlas sidebar.
 * 3. Generate an API Key and get your App ID/URL.
 */
const MONGODB_CONFIG = {
  endpoint: "https://data.mongodb-api.com/app/data-api-v1/action", // Replace with your actual endpoint
  apiKey: "YOUR_MONGODB_API_KEY", // Should be in .env (VITE_MONGODB_API_KEY)
  dataSource: "Cluster0",
  database: "blokm_bites",
  collection: "chat_history",
};

export class DatabaseService {
  private sessionId: string;

  constructor() {
    // Unique ID for the current user's device/session
    let storedId = localStorage.getItem('blokm_session_id');
    if (!storedId) {
      storedId = 'session_' + Math.random().toString(36).substring(2, 15);
      localStorage.setItem('blokm_session_id', storedId);
    }
    this.sessionId = storedId;
  }

  /**
   * Saves a single message to the MongoDB collection
   */
  async saveMessage(message: Message): Promise<boolean> {
    try {
      // If no API key is provided, we skip (graceful fallback)
      if (MONGODB_CONFIG.apiKey === "YOUR_MONGODB_API_KEY") return false;

      const response = await fetch(`${MONGODB_CONFIG.endpoint}/insertOne`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'api-key': MONGODB_CONFIG.apiKey,
        },
        body: JSON.stringify({
          dataSource: MONGODB_CONFIG.dataSource,
          database: MONGODB_CONFIG.database,
          collection: MONGODB_CONFIG.collection,
          document: {
            ...message,
            sessionId: this.sessionId,
            createdAt: new Date().toISOString()
          }
        })
      });

      return response.ok;
    } catch (error) {
      console.warn("MongoDB Save Error (likely not configured):", error);
      return false;
    }
  }

  /**
   * Fetches chat history for the current session
   */
  async getChatHistory(): Promise<Message[]> {
    try {
      if (MONGODB_CONFIG.apiKey === "YOUR_MONGODB_API_KEY") return [];

      const response = await fetch(`${MONGODB_CONFIG.endpoint}/find`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'api-key': MONGODB_CONFIG.apiKey,
        },
        body: JSON.stringify({
          dataSource: MONGODB_CONFIG.dataSource,
          database: MONGODB_CONFIG.database,
          collection: MONGODB_CONFIG.collection,
          filter: { sessionId: this.sessionId },
          sort: { createdAt: 1 }
        })
      });

      const data = await response.json();
      return data.documents || [];
    } catch (error) {
      console.warn("MongoDB Fetch Error:", error);
      return [];
    }
  }
}

import React, { useState, useRef, useEffect } from 'react';
import { ChatInterface } from './components/ChatInterface';
import { Header } from './components/Header';
import { GeminiService } from './services/geminiService';
import { DatabaseService } from './services/databaseService';
import { Message, ChatState } from './types';

const INITIAL_MESSAGE: Message = {
  id: 'init-1',
  role: 'model',
  content: "Hi! I'm your Blok M food guide. I'm connected to MongoDB to keep your history safe.\n\nWhat are you craving today? 🍜☕",
  timestamp: new Date(),
};

const INITIAL_SUGGESTIONS = [
  "Best Coffee for WFC 💻",
  "Spicy Food under 50k 🌶️",
  "Japanese Hidden Gems 🍱",
  "Dessert spots 🍰"
];

const getSmartSuggestions = (context: string): string[] => {
  const lower = context.toLowerCase();
  if (lower.includes('coffee') || lower.includes('cafe')) return ["📶 Fast wifi?", "🔌 Power outlets?", "🥐 Best pastry?"];
  if (lower.includes('japanese') || lower.includes('ramen')) return ["🍣 Sushi spots", "🍜 Best Ramen", "✅ Halal?"];
  return ["💸 Under 50k", "⭐ Highly rated", "📍 Near MRT", "🔥 Viral right now"];
};

export default function App() {
  const [chatState, setChatState] = useState<ChatState>({
    messages: [INITIAL_MESSAGE],
    isLoading: false,
    error: null,
  });

  const [dbStatus, setDbStatus] = useState<'idle' | 'syncing' | 'synced' | 'error'>('idle');
  const [suggestions, setSuggestions] = useState<string[]>(INITIAL_SUGGESTIONS);

  const geminiServiceRef = useRef<GeminiService | null>(null);
  const dbServiceRef = useRef<DatabaseService | null>(null);

  // Initialize Services & Load History
  useEffect(() => {
    geminiServiceRef.current = new GeminiService();
    dbServiceRef.current = new DatabaseService();

    const loadHistory = async () => {
      setDbStatus('syncing');
      const history = await dbServiceRef.current!.getChatHistory();
      if (history.length > 0) {
        setChatState(prev => ({ ...prev, messages: history }));
        setDbStatus('synced');
      } else {
        setDbStatus('idle');
      }
    };

    loadHistory();
  }, []);

  const handleSendMessage = async (text: string) => {
    if (!text.trim()) return;
    setSuggestions([]);

    const userMsg: Message = {
      id: Date.now().toString(),
      role: 'user',
      content: text,
      timestamp: new Date(),
    };

    // Optimistically update UI
    setChatState((prev) => ({
      ...prev,
      messages: [...prev.messages, userMsg],
      isLoading: true,
      error: null,
    }));

    // Persist User Message to MongoDB
    dbServiceRef.current?.saveMessage(userMsg);

    const aiMsgId = (Date.now() + 1).toString();
    const aiMsg: Message = {
      id: aiMsgId,
      role: 'model',
      content: '',
      timestamp: new Date(),
    };

    setChatState((prev) => ({
      ...prev,
      messages: [...prev.messages, aiMsg],
    }));

    try {
      const stream = geminiServiceRef.current!.sendMessageStream(text);
      let fullText = "";
      let finalMetadata: any = undefined;

      for await (const chunk of stream) {
        if (chunk.text) fullText += chunk.text;
        if (chunk.groundingMetadata) finalMetadata = chunk.groundingMetadata;

        setChatState((prev) => {
          const newMessages = [...prev.messages];
          const targetIndex = newMessages.findIndex(m => m.id === aiMsgId);
          if (targetIndex !== -1) {
            newMessages[targetIndex] = {
              ...newMessages[targetIndex],
              content: fullText,
              groundingMetadata: finalMetadata || newMessages[targetIndex].groundingMetadata
            };
          }
          return { ...prev, messages: newMessages };
        });
      }

      // Once AI finishes, persist AI message to MongoDB
      const finishedAiMsg = { ...aiMsg, content: fullText, groundingMetadata: finalMetadata };
      setDbStatus('syncing');
      await dbServiceRef.current?.saveMessage(finishedAiMsg);
      setDbStatus('synced');

      setChatState(prev => ({ ...prev, isLoading: false }));
      setSuggestions(getSmartSuggestions(text));

    } catch (err: any) {
      setChatState((prev) => ({
        ...prev,
        isLoading: false,
        error: "Database or AI connection error. Please try again.",
      }));
      setDbStatus('error');
    }
  };

  return (
    <div className="flex flex-col h-screen w-full bg-gray-50">
      <Header dbStatus={dbStatus} />
      <main className="flex-1 overflow-hidden relative flex flex-col">
        <ChatInterface 
          messages={chatState.messages} 
          isLoading={chatState.isLoading} 
          onSendMessage={handleSendMessage}
          error={chatState.error}
          suggestions={suggestions}
        />
      </main>
    </div>
  );
}

