const MONGODB_CONFIG = {
  endpoint: "https://data.mongodb-api.com/app/data-api-v1/action",
  apiKey: "YOUR_MONGODB_API_KEY", // Set in .env as VITE_MONGODB_API_KEY
  dataSource: "Cluster0",
  database: "blokm_bites",
  collection: "tenants", // Now fetching from 'tenants' collection
};

export class DatabaseService {
  /**
   * Fetches the official list of F&B tenants in Blok M from MongoDB
   */
  async getTenants(): Promise<Tenant[]> {
    try {
      // Graceful fallback if not configured
      if (!MONGODB_CONFIG.apiKey || MONGODB_CONFIG.apiKey === "YOUR_MONGODB_API_KEY") {
        return this.getFallbackTenants();
      }

      const response = await fetch(`${MONGODB_CONFIG.endpoint}/find`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'api-key': MONGODB_CONFIG.apiKey,
        },
        body: JSON.stringify({
          dataSource: MONGODB_CONFIG.dataSource,
          database: MONGODB_CONFIG.database,
          collection: MONGODB_CONFIG.collection,
          filter: {},
          limit: 100
        })
      });

      if (!response.ok) throw new Error("DB Fetch Failed");

      const data = await response.json();
      return data.documents && data.documents.length > 0 
        ? data.documents 
        : this.getFallbackTenants();

    } catch (error) {
      console.warn("MongoDB Fetch Error - using fallback data:", error);
      return this.getFallbackTenants();
    }
  }

  private getFallbackTenants(): Tenant[] {
    return [
      { name: "Futago Ya", category: "Japanese/Udon", priceRange: "40k-80k", specialty: "Creamy Miso Udon", location: "Little Tokyo" },
      { name: "Haka Dimsum", category: "Chinese/Dimsum", priceRange: "30k-60k", specialty: "Shaomai & Cheong Fun", location: "Blok M Plaza area" },
      { name: "Claypot Popo", category: "Chinese Comfort", priceRange: "40k-70k", specialty: "Claypot Siram Egg", location: "Melawai" },
      { name: "Sembilan Nanmu", category: "Coffee/Bakery", priceRange: "30k-60k", specialty: "Artisan Pastries", location: "Little Tokyo" },
      { name: "Kopi Tuku", category: "Coffee", priceRange: "20k-40k", specialty: "Es Kopi Susu Tetangga", location: "Pasar Santa / Melawai" }
    ];
  }
}

import { GoogleGenAI, Chat } from "@google/genai";
