const MODEL_ID = 'gemini-2.5-flash';

export class GeminiService {
  private ai: GoogleGenAI;
  private chatSession: Chat | null = null;
  private tenants: Tenant[] = [];

  constructor() {
    let apiKey = '';
    // @ts-ignore
    if (typeof import.meta !== 'undefined' && import.meta.env) {
      // @ts-ignore
      apiKey = import.meta.env.VITE_API_KEY;
    }
    if (!apiKey && typeof process !== 'undefined' && process.env) {
      apiKey = process.env.API_KEY || '';
    }
    this.ai = new GoogleGenAI({ apiKey: apiKey });
  }

  public setTenants(tenants: Tenant[]) {
    this.tenants = tenants;
    // Reset session so new instructions are picked up
    this.chatSession = null;
  }

  private initChat() {
    const tenantContext = this.tenants.length > 0 
      ? `\n\n**VERIFIED TENANT DATABASE:**\n${this.tenants.map(t => `- ${t.name}: ${t.category}, Specialty: ${t.specialty}, Price: ${t.priceRange} (${t.location})`).join('\n')}`
      : "";

    const systemInstruction = `
You are a specialized Food & Beverage Guide for Blok M, Jakarta.

**YOUR KNOWLEDGE SOURCE:**
Use the provided Verified Tenant Database first. If a user asks for a recommendation, prioritize these spots. Use Google Search grounding to verify if they are currently viral or have updated hours.

**STRICT SCOPE:**
Only discuss Food & Drink in Blok M. Politely refuse other topics.

**STYLE:** Local, casual, brief, and trustworthy.${tenantContext}`;

    this.chatSession = this.ai.chats.create({
      model: MODEL_ID,
      config: {
        systemInstruction,
        tools: [{ googleSearch: {} }],
        temperature: 0.7,
      },
    });
  }

  async *sendMessageStream(message: string) {
    if (!this.chatSession) this.initChat();
    try {
      const result = await this.chatSession!.sendMessageStream({ message });
      for await (const chunk of result) {
        yield { 
          text: chunk.text, 
          groundingMetadata: chunk.candidates?.[0]?.groundingMetadata as GroundingMetadata | undefined 
        };
      }
    } catch (error) {
      console.error("Gemini API Error:", error);
      throw error;
    }
  }
}

import React, { useState, useRef, useEffect } from 'react';
import { ChatInterface } from './components/ChatInterface';
import { Header } from './components/Header';
import { GeminiService } from './services/geminiService';
import { DatabaseService } from './services/databaseService';
import { Message, ChatState, Tenant } from './types';

const INITIAL_MESSAGE: Message = {
  id: 'init-1',
  role: 'model',
  content: "Hi! I'm your Blok M guide. I've just synced with our tenant database to give you the most accurate recommendations.\n\nWhat are you craving today? 🍜☕",
  timestamp: new Date(),
};

const INITIAL_SUGGESTIONS = [
  "What's Viral?", "Best Coffee ☕", "Japanese Food 🍜", "Budget Friendly 💸"
];

export default function App() {
  const [chatState, setChatState] = useState<ChatState>({
    messages: [INITIAL_MESSAGE],
    isLoading: false,
    error: null,
  });

  const [dbStatus, setDbStatus] = useState<'idle' | 'syncing' | 'synced' | 'error'>('idle');
  const [tenantCount, setTenantCount] = useState(0);
  const [suggestions, setSuggestions] = useState<string[]>(INITIAL_SUGGESTIONS);

  const geminiServiceRef = useRef<GeminiService | null>(null);
  const dbServiceRef = useRef<DatabaseService | null>(null);

  useEffect(() => {
    geminiServiceRef.current = new GeminiService();
    dbServiceRef.current = new DatabaseService();

    const initData = async () => {
      setDbStatus('syncing');
      try {
        const tenants = await dbServiceRef.current!.getTenants();
        geminiServiceRef.current!.setTenants(tenants);
        setTenantCount(tenants.length);
        setDbStatus('synced');
      } catch (e) {
        setDbStatus('error');
      }
    };

    initData();
  }, []);

  const handleSendMessage = async (text: string) => {
    if (!text.trim()) return;
    setSuggestions([]);

    const userMsg: Message = {
      id: Date.now().toString(),
      role: 'user',
      content: text,
      timestamp: new Date(),
    };

    setChatState((prev) => ({
      ...prev,
      messages: [...prev.messages, userMsg],
      isLoading: true,
      error: null,
    }));

    const aiMsgId = (Date.now() + 1).toString();
    const aiMsg: Message = { id: aiMsgId, role: 'model', content: '', timestamp: new Date() };

    setChatState((prev) => ({ ...prev, messages: [...prev.messages, aiMsg] }));

    try {
      const stream = geminiServiceRef.current!.sendMessageStream(text);
      let fullText = "";
      let finalMetadata: any = undefined;

      for await (const chunk of stream) {
        if (chunk.text) fullText += chunk.text;
        if (chunk.groundingMetadata) finalMetadata = chunk.groundingMetadata;

        setChatState((prev) => {
          const newMessages = [...prev.messages];
          const targetIndex = newMessages.findIndex(m => m.id === aiMsgId);
          if (targetIndex !== -1) {
            newMessages[targetIndex] = {
              ...newMessages[targetIndex],
              content: fullText,
              groundingMetadata: finalMetadata || newMessages[targetIndex].groundingMetadata
            };
          }
          return { ...prev, messages: newMessages };
        });
      }

      setChatState(prev => ({ ...prev, isLoading: false }));
      setSuggestions(["More like this", "Show locations", "Check price range"]);

    } catch (err: any) {
      setChatState(prev => ({ ...prev, isLoading: false, error: "Failed to connect to AI." }));
    }
  };

  return (
    <div className="flex flex-col h-screen w-full bg-gray-50">
      <Header dbStatus={dbStatus} tenantCount={tenantCount} />
      <main className="flex-1 overflow-hidden relative flex flex-col">
        <ChatInterface 
          messages={chatState.messages} 
          isLoading={chatState.isLoading} 
          onSendMessage={handleSendMessage}
          error={chatState.error}
          suggestions={suggestions}
        />
      </main>
    </div>
  );
}

