import { GoogleGenAI, Chat } from "@google/genai";
import { GroundingMetadata, Tenant } from "../types";

const MODEL_ID = 'gemini-2.5-flash';

export interface LocationCoords {
  latitude: number;
  longitude: number;
}

export class GeminiService {
  private ai: GoogleGenAI;
  private chatSession: Chat | null = null;
  private tenants: Tenant[] = [];

  constructor() {
    let apiKey = '';
    // @ts-ignore
    if (typeof import.meta !== 'undefined' && import.meta.env) {
      // @ts-ignore
      apiKey = import.meta.env.VITE_API_KEY;
    }
    if (!apiKey && typeof process !== 'undefined' && process.env) {
      apiKey = process.env.API_KEY || '';
    }
    this.ai = new GoogleGenAI({ apiKey: apiKey });
  }

  public setTenants(tenants: Tenant[]) {
    this.tenants = tenants;
    this.chatSession = null;
  }

  private initChat(location?: LocationCoords) {
    const tenantContext = this.tenants.length > 0 
      ? `\n\n**VERIFIED TENANT LIST (With Addresses):**\n${this.tenants.map(t => `- ${t.name}: ${t.category}. Specialty: ${t.specialty}. Address: ${t.address || "N/A"}. Map: ${t.mapsUrl || "Use Google Maps tool"}`).join('\n')}`
      : "";

    const systemInstruction = `
You are a specialized Food & Beverage Guide for Blok M, Jakarta.

**YOUR PRIMARY GOAL:** Reduce decision fatigue by giving clear, location-aware food recommendations.

**MANDATORY LOCATION RULES:**
1. Whenever you recommend a place, you MUST include its address and a link to Google Maps.
2. If the place is in the Verified Tenant List, use that address and map link.
3. If it's NOT in the list, use the **Google Maps tool** to find its exact location and provide the grounding link.
4. When providing directions, mention how far it is from the user's current location (Lat: ${location?.latitude || "Unknown"}, Lng: ${location?.longitude || "Unknown"}).

**TONE:** Jakarta local, casual, and efficient.${tenantContext}`;

    this.chatSession = this.ai.chats.create({
      model: MODEL_ID,
      config: {
        systemInstruction,
        tools: [
          { googleSearch: {} },
          { googleMaps: {} }
        ],
        toolConfig: location ? {
          retrievalConfig: {
            latLng: {
              latitude: location.latitude,
              longitude: location.longitude
            }
          }
        } : undefined,
        temperature: 0.6,
      },
    });
  }

  async *sendMessageStream(message: string, location?: LocationCoords) {
    if (!this.chatSession) {
      this.initChat(location);
    }

    try {
      const result = await this.chatSession!.sendMessageStream({ message });
      for await (const chunk of result) {
        yield { 
          text: chunk.text, 
          groundingMetadata: chunk.candidates?.[0]?.groundingMetadata as GroundingMetadata | undefined 
        };
      }
    } catch (error) {
      console.error("Gemini API Error:", error);
      throw error;
    }
  }
}

