export class DatabaseService {
  async getTenants(): Promise<Tenant[]> {
    try {
      if (!MONGODB_CONFIG.apiKey || MONGODB_CONFIG.apiKey === "YOUR_MONGODB_API_KEY") {
        return this.getFallbackTenants();
      }

      const response = await fetch(`${MONGODB_CONFIG.endpoint}/find`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'api-key': MONGODB_CONFIG.apiKey,
        },
        body: JSON.stringify({
          dataSource: MONGODB_CONFIG.dataSource,
          database: MONGODB_CONFIG.database,
          collection: MONGODB_CONFIG.collection,
          filter: {},
          limit: 100
        })
      });

      if (!response.ok) throw new Error("DB Fetch Failed");

      const data = await response.json();
      return data.documents && data.documents.length > 0 
        ? data.documents 
        : this.getFallbackTenants();

    } catch (error) {
      console.warn("Using fallback tenant data with valid Google Maps links.");
